head.script:
scwin.initData = {};

/**
 * 팝업 클로즈시 화면 회색처리를 해제한다.
 * @param
 * @return
 */
scwin.onpageunload = function() {
	if (document.getElementById("_modal").style.display == "block") {
		document.getElementById("_modal").style.display = "none";
	}
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	scwin.param = JSON.parse($p.getPopupParam());
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSPB1400000");
	scwin.searchDatas();
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 착공일 초기설정
	scwin.initSearchParam();
	// 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("planBsnsNm", "");
	dmaSearchParam.set("planChargerEmpno", "");
	dmaSearchParam.set("planChargerNm", "");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function(row) {
	scwin.initData.row = row;

	var planBsnsNm = ibxPlanBsnsNm.getValue();
	var planChargerEmpno = dmaSearchParam.get("planChargerEmpno");

	var queryString = `?planBsnsNm=${planBsnsNm}`;
	queryString += `&planChargerEmpno=${planChargerEmpno}`;

	var option = {
		action : "pb/plancnstrc/retrieve-plan.do"
			+ queryString,
		method : "get",
		resData : dltPlanList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRow.setValue(dltPlanList.getRowCount());
	if (scwin.initData.row != undefined) {
		// 저장되었습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00327"));
		grdPlanList.setFocusedCell(scwin.initData.row, 0);
		scwin.initData.row = -1;
	}
};

/**
 * 셀을 선택 후 선택 버튼 클릭시 해당 내용을 상세내역으로 표출한다.
 * @param
 * @return
 */
scwin.btnSet_onclick = function() {
	if (btnSet.hasClass("hide")) {
		return;
	}
	var rowIndex = grdPlanList.getFocusedRowIndex();
	var rowData = dltPlanList.getRowJSON(rowIndex);

	$p.parent().dmaPlanCnstrc.setJSON(rowData);
	$p.parent().dmaPlanCnstrcOld.setJSON(rowData);

	$p.parent().scwin.initData.bPlan = false;
	//계획 상세보기 사용 여부
	$p.parent().scwin.disabledBySetcsc(rowData.ecsSetcscDivCd);
	$p.parent().scwin.setPlanDisabled();
	$p.parent().scwin.inqireEctcc(rowData.planEsntlId, "");

	// 모달 창 닫기
	$p.closePopup();
};

/**
 * 셀을 선택 후 수정 버튼 클릭시 해당 내용을 수정할 수 있는 모달을 호출한다.
 * @param
 * @return
 */
scwin.btnEdit_onclick = function() {
	var rowIndex = grdPlanList.getFocusedRowIndex();
	var rowData = dltPlanList.getRowJSON(rowIndex);

	if (rowIndex != -1) {
		if ($p.getPopupWindowList().length < 1) {
			scwin.bOpen = true;
			var url = "/ui/ecs/pb/ECSPB1400001.xml";
			var dataObj = {
				"dataMap" : rowData
			};

			var options = {
				id : "ECSPB1400001",
				title : "계획 수정",
				popupName : "계획 수정",
				width : 800,
				height : 450,
				top : 0,
				left : 0,
				modal : true,
				closeAction : "",
				popupParam : dataObj
			};
			comLib.openPopup($p, "ECSPB1400001", url, options);
			$p.getComponentById($p.getPopupId()).setDisabled(true);
			$p.getComponentById($p.getFrameId()).setDisabled(true);
		}
	} else {
		// {0} 자료(이)가 존재합니다. // 자료선택해주세요로 변경예정
		return comLib.alert($p, utilLib.getMessage("SCM.INFO.00044", "")[0]);
	}
};

/**
 * 클릭시 사원번호 조회 모달을 띄운다.
 * @param
 * @return
 */
scwin.ibxPlanChargerNm_onclick = function(e) {
	if ($p.getPopupWindowList().length < 1) {
		scwin.bOpen = true;
		var url = "/ui/ecs/zz/ECSUserSearchPopup.xml";
		var dataObj = {
			"dataMap" : dmaSearchParam.getID(),
			"dataKey" : {
				"empNo" : "planChargerEmpno",
				"empNm" : "planChargerNm"
			}
		};

		var options = {
			id : "ECSUserSearchPopup",
			title : "사용자 검색",
			popupName : "사용자 검색",
			width : 800,
			height : 600,
			top : 0,
			left : 0,
			modal : true,
			closeAction : "",
			popupParam : dataObj
		};
		comLib.openPopup($p, "ECSUserSearchPopup", url, options);
		$p.getComponentById($p.getPopupId()).setDisabled(true);
		$p.getComponentById($p.getFrameId()).setDisabled(true);
	}
};

scwin.grdPlanList_oncelldblclick = function(row, col, colId) {
	scwin.btnSet_onclick();
};
